proof fn phi_3_singleton_to_seq_no_extra(v: int, e: int)
    requires
        v != e,
    ensures
        !Set::empty().insert(v).to_seq().contains(e),
{
    if Set::empty().insert(v).to_seq().contains(e) {
        element_in_seq_exists_in_original_finite_set(Set::empty().insert(v), e);
    }
}

proof fn phi_5_not_in_set_not_in_to_seq(s: Set<int>, e: int)
    requires
        s.finite(),
        !s.contains(e),
    ensures
        !s.to_seq().contains(e),
{
    if s.to_seq().contains(e) {
        element_in_seq_exists_in_original_finite_set(s, e);
    }
}
